import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / processing fee ---
  it.todo("empty item list yields premium 5 G (only the processing fee)");

  // --- Base premiums per item type ---
  it.todo("single sword quote yields 105 G (100 base + 5 fee)");
  it.todo("single amulet quote yields 65 G (60 base + 5 fee)");
  it.todo("single staff quote yields 85 G (80 base + 5 fee)");
  it.todo("single potion quote yields 45 G (40 base + 5 fee)");

  // --- Component pricing & blocks ---
  it.todo("2 runes quote yields 55 G (50 base + 5 fee)");
  it.todo("3 runes quote yields 65 G (60 block base + 5 fee)");
  it.todo("4 runes quote yields 105 G (100 base, no block + 5 fee)");
  it.todo("7 runes quote yields 180 G (175 base + 5 fee)");
  it.todo("2 runes + 1 moonstone yields 80 G (75 base, no block — different types + 5 fee)");
  it.todo("3 runes + 3 moonstones yields 125 G (120 base, two separate blocks + 5 fee)");

  // --- Item modifiers ---
  it.todo("cursed sword adds 50% surcharge to that item — newcomer cursed sword premium 165 G");
  it.todo("sword enchantment exactly 5 adds 30% high-enchantment surcharge");
  it.todo("sword enchantment 4 has no high-enchantment surcharge");
  it.todo("cursed sword enchantment 5 applies both surcharges");

  // --- Policy-wide modifiers ---
  it.todo("loyalty discount applies at exactly 2 years with MHPCO");
  it.todo("first quote in scenario gets first-insurance surcharge; second quote gets follow-up discount");

  // --- Modifier scope on multi-item policies ---
  it.todo("policy with cursed sword + plain amulet — surcharge applies to cursed item base only (210 G before fee/other modifiers)");

  // --- Rounding ---
  it.todo("premium of 197.5 G rounds UP to 198 G (in MHPCO's favor)");

  // --- Quotes — error cases ---
  it.todo("unknown item type in quote exits non-zero (handled by runScenario throwing)");

  // --- Claims — basic ---
  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G");

  // --- Claims — enchantment threshold ---
  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% then deductible)");

  // --- Claims — dragon material ---
  it.todo("dragon sword, ench 5, damage 800 G → payout 700 G (full, then deductible)");

  // --- Claims — both clauses (50% wins) ---
  it.todo("dragon sword, ench 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
  it.todo("dragon sword, ench exactly 8, damage 1000 G → payout 400 G (50% applies, then deductible)");

  // --- Deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per damaged item)");

  // --- Multiple items of same type ---
  it.todo("two swords policy: insurance sum 2000 G, cap 4000 G");
  it.todo("two swords, both damaged → each damage gets its own deductible");
  it.todo("damages contain more entries of a type than insured → claim rejected (throws)");

  // --- Cap exhaustion ---
  it.todo("cursed sword premium modifiers don't raise cap — cap stays 2000 G");
  it.todo("sword + 3 runes: insurance sum 1750 G; block discount affects premium only, not insurance sum");
  it.todo("sword cap 2000 G, two successive 1500 G claims → first payout 1400, second payout 600, cap 0");

  // --- Claim — error cases ---
  it.todo("claim references item not in policy → throws (non-zero exit)");
  it.todo("claim with negative amount → throws (non-zero exit)");

  // --- Payout rounding ---
  it.todo("payout that yields 350.5 G rounds DOWN to 350 G (in MHPCO's favor)");

  // --- Integration examples ---
  it.todo("integration: newcomer cursed sword (steel, ench 3) — premium 165 G");
  it.todo("integration: long-standing customer's 2nd quote, cursed sword ench 7 — premium 160 G");
});

