input.newString:
const PROCESSING_FEE = 5;

const baseOf = (item: Item): number => (item.type === "sword" ? 100 : 0);

const quotePremium = (items: Item[]): number =>
  items.reduce((sum, item) => sum + baseOf(item), 0) + PROCESSING_FEE;

export const runScenario = (scenario: Scenario): ScenarioOutput => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") return { premium: quotePremium(step.items) };
    throw new Error("claim not implemented");
  });
  return { results };
};

