input.oldString:
const RUNE_BLOCK_SIZE = 3;
const RUNE_BLOCK_PRICE = 60;

const isRuneBlock = (items: Item[]): boolean =>
  items.length === RUNE_BLOCK_SIZE && items.every((item) => item.type === "rune");

const sumOfBasePrices = (items: Item[]): number =>
  items.reduce((total, item) => total + basePriceOf(item), 0);

const baseTotal = (items: Item[]): number =>
  isRuneBlock(items) ? RUNE_BLOCK_PRICE : sumOfBasePrices(items);

input.newString:
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;
const COMPONENT_TYPES: ReadonlySet<string> = new Set(["rune", "moonstone"]);

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const bucket = groups.get(item.type) ?? [];
    bucket.push(item);
    groups.set(item.type, bucket);
  }
  return groups;
};

const baseTotalForGroup = (type: string, group: Item[]): number => {
  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
    return COMPONENT_BLOCK_PRICE;
  }
  return group.reduce((total, item) => total + basePriceOf(item), 0);
};

const baseTotal = (items: Item[]): number => {
  let total = 0;
  for (const [type, group] of groupByType(items)) {
    total += baseTotalForGroup(type, group);
  }
  return total;
};

