const loyaltyDiscount = (base: number, customer: Customer): number =>
  isLoyalCustomer(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;

const premiumFor = (items: Item[], customer: Customer): number => {
  const base = baseTotal(items);
  return Math.ceil(
    base +
      itemSurchargesTotal(items) +
      firstInsuranceSurcharge(base) -
      loyaltyDiscount(base, customer) +
      PROCESSING_FEE,
  );
};

const runStep = (step: Step, customer: Customer): StepResult => {
  if (step.op === "quote") return { premium: premiumFor(step.items, customer) };
  throw new Error("claim not implemented");
};

export const runScenario = (scenario: Scenario): ScenarioOutput => ({
  results: scenario.steps.map((step) => runStep(step, scenario.customer)),
});

