const loyaltyDiscount = (base: number, customer: Customer): number =>
  isLoyalCustomer(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;

const followupDiscount = (base: number, isFollowup: boolean): number =>
  isFollowup ? base * FOLLOWUP_DISCOUNT_RATE : 0;

const policyAdjustments = (
  base: number,
  customer: Customer,
  isFollowup: boolean,
): number =>
  firstInsuranceSurcharge(base) -
  loyaltyDiscount(base, customer) -
  followupDiscount(base, isFollowup);

const premiumFor = (items: Item[], customer: Customer, isFollowup: boolean): number => {
  const base = baseTotal(items);
  const premium =
    base +
    itemSurchargesTotal(items) +
    policyAdjustments(base, customer, isFollowup) +
    PROCESSING_FEE;
  return Math.ceil(premium);
};

interface ScenarioState {
  quoteCount: number;
}

const runStep = (step: Step, customer: Customer, state: ScenarioState): StepResult => {
  if (step.op === "quote") {
    const isFollowup = state.quoteCount > 0;
    state.quoteCount += 1;
    return { premium: premiumFor(step.items, customer, isFollowup) };
  }
  throw new Error("claim not implemented");
};

export const runScenario = (scenario: Scenario): ScenarioOutput => {
  const state: ScenarioState = { quoteCount: 0 };
  return {
    results: scenario.steps.map((step) => runStep(step, scenario.customer, state)),
  };
};

