  const grossPayout = sumBy(incident.damages, payoutForDamage);
  const payout = Math.min(grossPayout, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
};

export const runScenario = (scenario: Scenario): ScenarioOutput => {
  let quoteCount = 0;
  const policies: Record<number, Policy> = {};
  const results = scenario.steps.map((step, index): StepResult => {
    if (step.op === "quote") {
      const isFollowup = quoteCount > 0;
      quoteCount += 1;
      policies[index] = newPolicy(step.items);
      return { premium: premiumFor(step.items, scenario.customer, isFollowup) };
    }
    return processClaim(policies[step.policy], step.incident);
  });
  return { results };
};

