const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;

const reimbursementRateFor = (item: Item): number =>
  isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_PAYOUT_RATE : 1;

const payoutForDamage = (damage: Damage, item: Item): number =>
  Math.max(0, damage.amount * reimbursementRateFor(item) - DEDUCTIBLE);

interface Policy {
  items: Item[];
  remainingCap: number;
}

const newPolicy = (items: Item[]): Policy => ({
  items,
  remainingCap: insuranceSumOf(items) * CAP_MULTIPLIER,
});

const findItem = (policy: Policy, itemType: string): Item => {
  const item = policy.items.find((it) => it.type === itemType);
  if (item === undefined) {
    throw new Error(`Policy does not insure item type: ${itemType}`);
  }
  return item;
};

const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
  const grossPayout = sumBy(incident.damages, (damage) =>
    payoutForDamage(damage, findItem(policy, damage.itemType)),
  );
  const payout = Math.min(grossPayout, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
};

