const isPayoutHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= PAYOUT_HIGH_ENCHANTMENT_THRESHOLD;

const reimbursementRateFor = (item: Item): number => {
  if (isPayoutHighlyEnchanted(item)) return HIGH_ENCHANTMENT_PAYOUT_RATE;
  if (isDragonMaterial(item)) return FULL_PAYOUT_RATE;
  return FULL_PAYOUT_RATE;
};

