const settleClaim = (policy: Policy, incident: Incident): { result: ClaimResult; policy: Policy } => {
  const grossPayout = sumBy(incident.damages, (damage) => payoutForDamage(damage, policy));
  const payout = Math.min(grossPayout, policy.remainingCap);
  const remainingCap = policy.remainingCap - payout;
  return {
    result: { payout: Math.floor(payout), remainingCap },
    policy: { ...policy, remainingCap },
  };
};

input.newString:
const countByType = <T extends { type: string } | { itemType: string }>(
  entries: T[],
  keyOf: (entry: T) => string,
): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const entry of entries) {
    counts.set(keyOf(entry), (counts.get(keyOf(entry)) ?? 0) + 1);
  }
  return counts;
};

const validateDamagesAgainstPolicy = (policy: Policy, damages: Damage[]): void => {
  const insuredCounts = countByType(policy.items, (item) => item.type);
  const damageCounts = countByType(damages, (damage) => damage.itemType);
  for (const [itemType, damageCount] of damageCounts) {
    const insuredCount = insuredCounts.get(itemType) ?? 0;
    if (damageCount > insuredCount) {
      throw new Error(
        `Damage count for ${itemType} (${damageCount}) exceeds insured count (${insuredCount})`,
      );
    }
  }
};

const settleClaim = (policy: Policy, incident: Incident): { result: ClaimResult; policy: Policy } => {
  validateDamagesAgainstPolicy(policy, incident.damages);
  const grossPayout = sumBy(incident.damages, (damage) => payoutForDamage(damage, policy));
  const payout = Math.min(grossPayout, policy.remainingCap);
  const remainingCap = policy.remainingCap - payout;
  return {
    result: { payout: Math.floor(payout), remainingCap },
    policy: { ...policy, remainingCap },
  };
};

